This is a complete, single-file HTML solution. It uses **Three.js** (a popular 3D library) to procedurally generate a house.

Since I cannot send you a physical `.obj` or `.gltf` file, I have written code that **builds the house geometry from scratch** (walls, roof, windows, door) so you can see it immediately in your browser.

### How to use this:
1.  Copy the code below.
2.  Save it as an `.html` file (e.g., `house.html`).
3.  Open that file in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Left Click: Rotate | Right Click: Pan | Scroll: Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. SCENE SETUP ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // --- 2. CONTROLS ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // --- 3. LIGHTING ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 4. MATERIALS ---
        const materials = {
            wall: new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.8 }),
            roof: new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.9 }),
            wood: new THREE.MeshStandardMaterial({ color: 0x5c4033 }),
            glass: new THREE.MeshStandardMaterial({ color: 0x88ccff, transparent: true, opacity: 0.6 }),
            grass: new THREE.MeshStandardMaterial({ color: 0x4caf50 })
        };

        // --- 5. BUILD THE HOUSE ---
        const houseGroup = new THREE.Group();
        scene.add(houseGroup);

        // Helper function to create walls
        function createWall(w, h, d, x, y, z, mat) {
            const geo = new THREE.BoxGeometry(w, h, d);
            const mesh = new THREE.Mesh(geo, mat);
            mesh.position.set(x, y, z);
            mesh.castShadow = true;
            mesh.receiveShadow = true;
            return mesh;
        }

        // Main Body
        const mainBody = createWall(8, 4, 8, 0, 2, 0, materials.wall);
        houseGroup.add(mainBody);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 3, 4);
        const roof = new THREE.Mesh(roofGeo, materials.roof);
        roof.position.set(0, 6, 0);
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Chimney
        const chimney = createWall(1.5, 2, 1, 3, 5, 0, materials.wall);
        houseGroup.add(chimney);

        // --- 6. WINDOWS ---
        function createWindow(x, y, z, w, h) {
            const frameGeo = new THREE.BoxGeometry(w + 0.1, h + 0.1, 0.2);
            const frame = new THREE.Mesh(frameGeo, materials.wood);
            frame.position.set(x, y, z);

            const glassGeo = new THREE.PlaneGeometry(w, h);
            const glass = new THREE.Mesh(glassGeo, materials.glass);
            glass.position.set(x, y, z + 0.11); // Slightly in front of frame

            houseGroup.add(frame);
            houseGroup.add(glass);
        }

        // Front Windows
        createWindow(0, 3, 4, 1.5, 1.5);
        createWindow(0, 1, 4, 1.5, 1.5);

        // Side Window
        createWindow(4, 3, 0, 1.5, 1.5);

        // --- 7. DOOR ---
        const doorFrame = createWall(1.5, 2.5, 0.2, 0, 1.25, 4, materials.wood);
        const doorMesh = new THREE.Mesh(new THREE.BoxGeometry(1.5, 2.5, 0.1), materials.wood);
        doorMesh.position.set(0, 1.25, 4.05);
        houseGroup.add(doorFrame);
        houseGroup.add(doorMesh);

        // --- 8. GROUND ---
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, materials.grass);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // --- 9. ANIMATION LOOP ---
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Key Features of this Code:
1.  **Procedural Generation:** It builds the house using geometric primitives (Boxes, Cones, Planes) rather than loading an external file. This ensures it works instantly without CORS errors or missing file paths.
2.  **Lighting & Shadows:** It includes a Directional Light (simulating the sun) that casts realistic shadows on the ground and the house itself.
3.  **Interactivity:** I included `OrbitControls`. You can:
    *   **Left Click + Drag:** Rotate around the house.
    *   **Right Click + Drag:** Pan the view.
    *   **Scroll:** Zoom in and out.
4.  **Materials:** It uses `MeshStandardMaterial` to react to light, giving the roof a matte finish and the windows a slight transparency.
